#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

function readIssue(issuePathArg) {
  if (!issuePathArg) {
    throw new Error('Missing path to issue JSON (first argument).');
  }

  const issuePath = path.resolve(process.cwd(), issuePathArg);
  if (!fs.existsSync(issuePath)) {
    throw new Error(`Issue JSON file not found: ${issuePath}`);
  }

  let parsed;
  try {
    parsed = JSON.parse(fs.readFileSync(issuePath, 'utf8'));
  } catch (error) {
    throw new Error(`Failed to parse issue JSON: ${error.message}`);
  }

  if (!parsed || typeof parsed !== 'object') {
    throw new Error('Issue JSON must be an object.');
  }

  if (!Number.isInteger(parsed.number) || parsed.number <= 0) {
    throw new Error('Issue JSON "number" must be a positive integer.');
  }

  if (typeof parsed.title !== 'string' || parsed.title.trim() === '') {
    throw new Error('Issue JSON "title" must be a non-empty string.');
  }

  if (parsed.body != null && typeof parsed.body !== 'string') {
    throw new Error('Issue JSON "body" must be a string when present.');
  }

  return {
    number: parsed.number,
    title: parsed.title.trim(),
    body: parsed.body || ''
  };
}

function generateFallbackMarkdown(issue) {
  return [
    `# Issue #${issue.number}: ${issue.title}`,
    '',
    '## Context',
    '',
    issue.body.trim() || '_No issue body provided._',
    '',
    '## Fallback Generator Note',
    '',
    'This file was generated by the Node-only fallback generator.',
    ''
  ].join('\n');
}

function main() {
  const issue = readIssue(process.argv[2]);
  const outDir = path.join(process.cwd(), '.autogen');
  fs.mkdirSync(outDir, { recursive: true });

  const outputPath = path.join(outDir, `issue-${issue.number}.md`);
  fs.writeFileSync(outputPath, generateFallbackMarkdown(issue), 'utf8');
  console.log(`Generated fallback file: ${outputPath}`);
}

try {
  main();
} catch (error) {
  console.error(error.message);
  process.exit(1);
}
